def min_operations(nums):
    n = len(nums)
    even, odd = 0, 0

    for i in range(n):
        if i % 2 == 0 and nums[i] % 2 != 0:
            even += 1
        elif i % 2 != 0 and nums[i] % 2 == 0:
            odd += 1

    return min(even, odd)
```

