public int minOperations(int[] nums) {
    int n = nums.length;
    int even = 0, odd = 0;

    for (int i = 0; i < n; ++i) {
        if (i % 2 == 0 && nums[i] % 2 != 0) {
            even++;
        } else if (i % 2 != 0 && nums[i] % 2 == 0) {
            odd++;
        }
    }

    return Math.min(even, odd);
}
